            (0.64, 0.80, 0.90),   # soft sky blue — warm pastel, not cold
            (0.92, 0.80, 0.54),   # warm golden sunlight — his characteristic afternoon glow
            (0.72, 0.54, 0.70),   # soft lavender-pink drapery — ribbons, silks, petticoats
