            (0.06, 0.50, 0.22),   # saturated emerald — foliage, background
            (0.92, 0.84, 0.68),   # pale ivory flesh — lit skin on copper ground
            (0.20, 0.14, 0.08),   # deep umber shadow — Mannerist void depths
