            (0.88, 0.68, 0.22),   # golden amber — agitated warmth and near-sunset glow
            (0.35, 0.55, 0.40),   # muted sage — Norwegian landscape distance
            (0.72, 0.55, 0.48),   # warm flesh — figure tones, face and hands
