            (0.45, 0.40, 0.28),   # raw sienna brown — warm fabric and wood
            (0.62, 0.62, 0.55),   # cool grey-green — walls, backgrounds
            (0.80, 0.50, 0.22),   # accent cadmium-orange — textile or skin warmth
